import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import Hero from './features/landing/Hero';
import JobServices from './features/landing/JobServices';
import JobListContainer from './features/eksplorasi/JobListContainer';

// Komponen Pembantu untuk Tombol "Lihat Semua"
const ViewAllButton = () => {
    const navigate = useNavigate();
    return (
        <div style={{ textAlign: 'center', marginTop: '30px' }}>
            <button onClick={() => navigate('/eksplorasi')} style={{ padding: '12px 30px', background: '#ea580c', color: '#fff', border: 'none', borderRadius: '10px', cursor: 'pointer' }}>
                Semua Lowongan
            </button>
        </div>
    );
};

const App = () => {
    const [isAuthenticated] = useState(!!localStorage.getItem('token'));

    return (
        <Router>
            <div className="flex flex-col min-h-screen bg-black text-white">
                <Navbar />
                <main className="flex-grow">
                    <Routes>
                        <Route path="/" element={
                            <>
                                <Hero />
                                <section style={{ padding: '40px 80px' }}>
                                    <h2 style={{ fontSize: '24px', marginBottom: '20px' }}>Lowongan Terbaru</h2>
                                    <JobListContainer limit={3} /> 
                                    <ViewAllButton />
                                </section>
                            </>
                        } />
                        <Route path="/eksplorasi" element={
                            <div style={{ padding: '40px 80px' }}>
                                <h1 style={{ marginBottom: '20px' }}>Seluruh Lowongan Kerja</h1>
                                <JobListContainer />
                            </div>
                        } />
                    </Routes>
                </main>
                <Footer />
            </div>
        </Router>
    );
};

export default App;
